"use client";
import { Button } from "@daveyplate/better-auth-ui";
import { authClient } from "@/lib/auth-client";

export default function LogoutButton() {
    return (
        <Button
            variant="outline"
            onClick={async () => {
                await authClient.signOut();
                window.location.reload();
            }}
        >
            Sair
        </Button>
    );
}
